import { Button } from "@repo/ui/components/ui/button";
import type {
  FAQPage,
  GraphContext,
  Organization,
  Question,
  SoftwareApplication,
  WebSite,
} from "@vendor/seo/json-ld";
import { JsonLd } from "@vendor/seo/json-ld";
import { Link as MicrofrontendLink } from "@vercel/microfrontends/next/client";
import type { Metadata } from "next";
import { ChangelogPreview } from "~/app/(app)/_components/changelog-preview";
import { FAQSection, faqs } from "~/app/(app)/_components/faq-section";
import { HeroChangelogBadge } from "~/app/(app)/_components/hero-changelog-badge";
import { WaitlistCTA } from "~/app/(app)/_components/waitlist-cta";
import {
  HAIRLINE_X_PCT,
  HAIRLINE_Y_PCT,
  IsometricHero,
} from "./_components/isometric-hero";

// SEO metadata for the landing page
export const metadata: Metadata = {
  title: "Superintelligence Layer for Founders",
  description:
    "Lightfast is the superintelligence layer for founders. Built on a unified operating layer that connects your tools, unifies your agents, and orchestrates your entire operation.",
  keywords: [
    "superintelligence",
    "AI for founders",
    "founder tools",
    "operating infrastructure",
    "agent infrastructure",
    "event-driven architecture",
    "tool integration",
    "MCP tools",
    "AI agent platform",
    "real-time events",
    "operating layer",
    "agents and apps",
    "observe remember act",
  ],
  authors: [{ name: "Lightfast", url: "https://lightfast.ai" }],
  creator: "Lightfast",
  publisher: "Lightfast",
  robots: {
    index: true,
    follow: true,
    googleBot: {
      index: true,
      follow: true,
      "max-video-preview": -1,
      "max-image-preview": "large",
      "max-snippet": -1,
    },
  },
  alternates: {
    canonical: "https://lightfast.ai",
  },
  openGraph: {
    title: "Lightfast – Superintelligence Layer for Founders",
    description:
      "The superintelligence layer for founders. Built on a unified operating layer — your tools, your agents, your entire operation orchestrated in one place.",
    url: "https://lightfast.ai",
    siteName: "Lightfast",
    type: "website",
    locale: "en_US",
  },
  twitter: {
    card: "summary_large_image",
    title: "Lightfast – Superintelligence Layer for Founders",
    description:
      "The superintelligence layer for founders. Built on a unified operating layer — your tools, your agents, your entire operation orchestrated in one place.",
    site: "@lightfastai",
    creator: "@lightfastai",
  },
  category: "Technology",
};

export default function HomePage() {
  // Build organization entity
  const organizationEntity: Organization = {
    "@type": "Organization",
    "@id": "https://lightfast.ai/#organization",
    name: "Lightfast",
    url: "https://lightfast.ai",
    logo: {
      "@type": "ImageObject",
      url: "https://lightfast.ai/android-chrome-512x512.png",
    },
    sameAs: [
      "https://twitter.com/lightfastai",
      "https://github.com/lightfastai",
      "https://www.linkedin.com/company/lightfastai",
    ],
    description:
      "Lightfast is the superintelligence layer for founders. Built on a unified operating layer that connects tools, unifies agents, and orchestrates entire operations through one system.",
  };

  // Build website entity
  const websiteEntity: WebSite = {
    "@type": "WebSite",
    "@id": "https://lightfast.ai/#website",
    url: "https://lightfast.ai",
    name: "Lightfast",
    description:
      "Superintelligence layer for founders — built on a unified operating layer to observe, remember, and act across every tool.",
    publisher: {
      "@id": "https://lightfast.ai/#organization",
    },
  };

  // Build software application entity
  const softwareEntity: SoftwareApplication = {
    "@type": "SoftwareApplication",
    "@id": "https://lightfast.ai/#software",
    name: "Lightfast",
    applicationCategory: "BusinessApplication",
    operatingSystem: "Web, API",
    offers: {
      "@type": "Offer",
      price: "0",
      priceCurrency: "USD",
      url: "https://lightfast.ai/early-access",
    },
    description:
      "The superintelligence layer for founders. Built on a unified operating layer — observe events, build memory, and orchestrate action across your entire tool stack through a single system.",
    featureList: [
      "Real-time event ingestion from connected tools",
      "Semantic search with cited sources",
      "MCP tools for AI agents",
      "REST API and TypeScript SDK",
      "Intent-based action resolution",
      "Complete tenant isolation",
      "Webhook event delivery",
    ],
  };

  // Build FAQ entity
  const faqEntity: FAQPage = {
    "@type": "FAQPage",
    "@id": "https://lightfast.ai/#faq",
    mainEntity: faqs.map((faq) => {
      const question: Question = {
        "@type": "Question",
        name: faq.question,
        acceptedAnswer: {
          "@type": "Answer",
          text: faq.answer,
        },
      };
      return question;
    }),
  };

  // Combine all entities in a graph
  const structuredData: GraphContext = {
    "@context": "https://schema.org",
    "@graph": [organizationEntity, websiteEntity, softwareEntity, faqEntity],
  };

  return (
    <>
      {/* Structured data for SEO */}
      <JsonLd code={structuredData} />

      {/* Grid-based landing page */}
      <div className="min-h-screen bg-background">
        {/* Hero Section */}
        <section className="relative min-h-screen w-full overflow-clip bg-background">
          {/* Right: Isometric Lissajous SVG — golden ratio from top, right-aligned */}
          <div className="pointer-events-none absolute inset-0 z-0 hidden items-center justify-end lg:flex">
            <div className="relative mr-24 w-[55%] max-w-[750px]">
              {/* Horizontal extension lines — from card edges to viewport edges */}
              <div
                className="absolute right-full h-px w-[100vw]"
                style={{
                  top: `${HAIRLINE_Y_PCT}%`,
                  backgroundColor: "var(--border)",
                }}
              />
              <div
                className="absolute left-full h-px w-[100vw]"
                style={{
                  top: `${HAIRLINE_Y_PCT}%`,
                  backgroundColor: "var(--border)",
                }}
              />
              {/* Vertical extension lines — from card edges to section edges */}
              <div
                className="absolute bottom-full w-px h-[100vh]"
                style={{
                  left: `${HAIRLINE_X_PCT}%`,
                  backgroundColor: "var(--border)",
                }}
              />
              <IsometricHero />
            </div>
          </div>

          {/* Left: Text + CTA — above the horizontal hairline */}
          <div className="relative z-20 mx-auto flex min-h-screen w-full max-w-[1400px] items-start px-8 pt-[18vh] pb-24 md:px-16 md:pt-[15vh] md:pb-32 lg:items-end lg:px-24 lg:pt-0 lg:pb-[56vh]">
            <div className="flex w-full max-w-sm flex-col justify-center md:max-w-lg lg:max-w-sm">
              <h1 className="mb-4 font-medium font-pp text-4xl md:text-3xl lg:text-3xl">
                <span className="text-muted-foreground">Building the</span>{" "}
                <span className="text-primary">superintelligence layer</span>{" "}
                <span className="text-muted-foreground">for</span>{" "}
                <span className="text-primary">teams and agents.</span>
              </h1>
              <div>
                <Button asChild size="sm">
                  <MicrofrontendLink href="/early-access" prefetch={true}>
                    Join Early Access
                    <span className="ml-2">→</span>
                  </MicrofrontendLink>
                </Button>
              </div>
            </div>
          </div>

          {/* Mobile: Isometric SVG below text */}
          <div className="px-8 pb-24 md:px-16 lg:hidden">
            <IsometricHero />
          </div>

          {/* Changelog badge - pinned to bottom of initial viewport */}
          <div className="pointer-events-none absolute inset-x-0 top-0 z-30 flex h-screen items-end pb-8">
            <div className="mx-auto w-full max-w-[1400px] px-8 md:px-16 lg:px-24">
              <div className="pointer-events-auto">
                <HeroChangelogBadge />
              </div>
            </div>
          </div>
        </section>

        {/* FAQ Section */}
        <section className="w-full bg-background py-24 md:py-32">
          <div className="mx-auto w-full max-w-[1400px] px-8 md:px-16 lg:px-24">
            <FAQSection />
          </div>
        </section>

        {/* Changelog Preview */}
        <section className="w-full bg-background py-24 md:py-32">
          <div className="mx-auto w-full max-w-[1400px] px-8 md:px-16 lg:px-24">
            <ChangelogPreview />
          </div>
        </section>
      </div>

      {/* CTA Section */}
      <WaitlistCTA />
    </>
  );
}

import {
  lissajousPoints as computeLissajousPoints,
  LOGO_CURVE,
} from "@repo/ui/lib/brand";
import type { Box3D, Vec2 } from "@repo/ui/lib/iso";
import { createBox, facePath, project, shapeBounds } from "@repo/ui/lib/iso";

const CANVAS_W = 1200;
const CANVAS_H = 675;

const BOX: Box3D = { x: 0, y: 0, z: 0, w: 220, h: 220, d: 22 };
const LISSAJOUS_RADIUS = 76;
const STEPS = 512;

const shape = createBox(BOX);
const bounds = shapeBounds(shape);

const PAD = 4;
const vx = bounds.minX - PAD;
const vy = bounds.minY - PAD;
const vw = bounds.maxX - bounds.minX + PAD * 2;
const vh = bounds.maxY - bounds.minY + PAD * 2;

// Golden-ratio framing — focal point at upper-RIGHT power point
const PHI_INV_SQ = 0.381_966_011_250_105_1;
const ANCHOR_X = CANVAS_W * (1 - PHI_INV_SQ); // ~61.8% from left
const ANCHOR_Y = CANVAS_H * PHI_INV_SQ; // ~38.2% from top

const focalIso = project(BOX.x + BOX.w / 2, BOX.y + BOX.h / 2, BOX.z + BOX.d);

function isoToCanvas([ix, iy]: Vec2): Vec2 {
  return [ANCHOR_X + (ix - focalIso[0]), ANCHOR_Y + (iy - focalIso[1])];
}

// Extreme projected corners for hairlines
const bottomZ = BOX.z;
const topZB = BOX.z + BOX.d;
const leftCorner = isoToCanvas(project(BOX.x, BOX.y + BOX.h, bottomZ));
const rightCorner = isoToCanvas(project(BOX.x + BOX.w, BOX.y, bottomZ));
const topCorner = isoToCanvas(project(BOX.x, BOX.y, topZB));

// Box SVG position within the canvas
const BOX_LEFT = ANCHOR_X - (focalIso[0] - vx);
const BOX_TOP = ANCHOR_Y - (focalIso[1] - vy);

const topZ = BOX.z + BOX.d;
const cx = BOX.x + BOX.w / 2;
const cy = BOX.y + BOX.h / 2;

const lissajousProjected: Vec2[] = computeLissajousPoints(
  LOGO_CURVE.a,
  LOGO_CURVE.b,
  LOGO_CURVE.delta,
  STEPS,
)
  .slice(0, STEPS)
  .map(([px, py]) =>
    project(cx + LISSAJOUS_RADIUS * px, cy + LISSAJOUS_RADIUS * py, topZ),
  );

const lissajousPath = `${lissajousProjected
  .map((v, i) => `${i === 0 ? "M" : "L"}${v[0].toFixed(2)},${v[1].toFixed(2)}`)
  .join(" ")} Z`;

const faces = shape.faces;

/** Horizontal hairline Y as % of canvas height — both left and right hairlines share this Y. */
export const HAIRLINE_Y_PCT = (leftCorner[1] / CANVAS_H) * 100;

/** Vertical hairline X as % of canvas width — both top and bottom hairlines share this X. */
export const HAIRLINE_X_PCT = (topCorner[0] / CANVAS_W) * 100;

export function IsometricHero() {
  return (
    <div className="aspect-video w-full overflow-hidden rounded-md bg-">
      <svg
        className="h-full w-full"
        viewBox={`0 0 ${CANVAS_W} ${CANVAS_H}`}
        xmlns="http://www.w3.org/2000/svg"
      >
        {/* Hairlines from box corners to canvas edges */}
        <line
          stroke="var(--border)"
          strokeWidth={1}
          vectorEffect="non-scaling-stroke"
          x1={0}
          x2={leftCorner[0]}
          y1={leftCorner[1]}
          y2={leftCorner[1]}
        />
        <line
          stroke="var(--border)"
          strokeWidth={1}
          vectorEffect="non-scaling-stroke"
          x1={rightCorner[0]}
          x2={CANVAS_W}
          y1={rightCorner[1]}
          y2={rightCorner[1]}
        />
        <line
          stroke="var(--border)"
          strokeWidth={1}
          vectorEffect="non-scaling-stroke"
          x1={topCorner[0]}
          x2={topCorner[0]}
          y1={0}
          y2={topCorner[1]}
        />

        {/* Isometric box faces + Lissajous curve */}
        <g transform={`translate(${BOX_LEFT - vx}, ${BOX_TOP - vy})`}>
          {faces.map((face, i) => (
            <path
              d={facePath(face)}
              fill="var(--background)"
              fillRule="evenodd"
              key={`${face.type}-${i}`}
              stroke="var(--border)"
              strokeWidth={1}
            />
          ))}
          <path
            d={lissajousPath}
            fill="none"
            stroke="var(--border)"
            strokeWidth={1}
          />
        </g>
      </svg>
    </div>
  );
}

